+            "SELECT typeof(created_ts) AS ct, created_ts AS cv, \
+                    typeof(updated_ts) AS ut, updated_ts AS uv, \
+                    expires_ts IS NULL AS expires_null \
+             FROM agent_links WHERE id = 1",
